/// GET v1/{+name}
/// Updates an SSH public key and returns the profile information. This method supports patch semantics.
///
/// Returns `ClientRequestBuilder` for customization.
/// Use `oslogin_users_ssh_public_keys_patch_execute()` to send, or `oslogin_users_ssh_public_keys_patch` for simplest API.

pub fn oslogin_users_ssh_public_keys_patch_builder(
    client: &SimpleHttpClient,
    name: &str,
    updateMask: Option<&str>,
    body: &SshPublicKey,
) -> Result<ClientRequestBuilder<SystemDnsResolver>, ApiError> {
    // Build URL
    let url = format!("https://api.example.comv1/{+name}", name,);

    // Build request
    client
        .get(&url)
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))
        .query(
            "updateMask",
            updateMask
                .as_ref()
                .map(|s| s.to_string())
                .unwrap_or_default()
                .as_str(),
        )
        .body_json(body)
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))?
}

